use std::fmt;
use std::error::Error;

#[derive(Debug)]
struct JobError {
    kind: ErrorKind,
    message: String,
}

impl fmt::Display for JobError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Job failed due to {:?}: {}", self.kind, self.message)
    }
}

impl Error for JobError {}

#[derive(Debug)]
enum ErrorKind {
    NetworkIssue,
    PermissionDenied,
    ResourceExhausted,
    UnknownFailure,
}

struct PipelineRunner {
    job_name: String,
}

impl PipelineRunner {
    fn new(job_name: &str) -> Self {
        PipelineRunner { job_name: job_name.to_string() }
    }

    fn execute_step(&self, attempt: u8) -> Result<(), Box<dyn Error>> {
        if attempt == 1 {
            return Err(Box::new(JobError {
                kind: ErrorKind::NetworkIssue,
                message: "Could not connect to remote service during initial sync".to_string(),
            }));
        } else if attempt == 2 {
            return Err(Box::new(JobError {
                kind: ErrorKind::PermissionDenied,
                message: "The job user lacks write access to the required directory".to_string(),
            }));
        }

        println!("Successfully completed step for {} on attempt {}", self.job_name, attempt);
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let runner = PipelineRunner::new("BuildReleaseJob");

    match runner.execute_step(1) {
        Err(e) => {
            println!("Caught initial error: {}", e);
            if let Some(job_err) = e.downcast_ref::<JobError>() {
                match job_err.kind {
                    ErrorKind::NetworkIssue => println!("Attempting retry due to network glitch... (Simulating)"),
                    _ => println!("Fatal error kind encountered."),
                }
            }
        }
        Ok(_) => {}
    }

    match runner.execute_step(2) {
        Err(e) => {
            println!("Caught second error: {}", e);
        }
        Ok(_) => {}
    }

    match runner.execute_step(3) {
        Err(e) => println!("Unexpected failure during final step: {}", e),
        Ok(_) => {}
    }

    Ok(())
}

use std::io;

struct PluginExecutionResult {
    success: bool,
    output: String,
}

fn execute_plugin(path: &str) -> Result<PluginExecutionResult, io::Error> {
    let _ = std::fs::read_to_string(path);
    Ok(PluginExecutionResult { success: true, output: format!("Executed successfully for {}", path) })
}

fn check_plugin_error(result: Result<PluginExecutionResult, io::Error>) -> Option<&'static str> {
    match result {
        Ok(_) => None,
        Err(e) if e.kind() == io::ErrorKind::NotFound => Some("File Not Found Kind"),
        Err(_) => Some("Other Error Kind")
    }
}

fn main() -> io::Result<()> {
    let missing_result = execute_plugin("non_existent_file.wasm");
    if let Some(kind) = check_plugin_error(missing_result) {
        println!("Detected error kind: {}", kind);
    }
    Ok(())
}

use std::fmt::{self, Display}; use std::error::Error; use std::io::ErrorKind;

#[derive(Debug)]
pub enum GameError {
    InsufficientResources(String),
    InvalidStateTransition(String),
    NetworkTimeout,
}

impl Display for GameError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            GameError::InsufficientResources(item) => write!(f, "Not enough of {}.", item),
            GameError::InvalidStateTransition(msg) => write!(f, "Bad move: {}", msg),
            GameError::NetworkTimeout => write!(f, "Connection dropped during save."),
        }
    }
}

impl From<std::io::Error> for GameError {
    fn from(err: std::io::Error) -> Self {
        if err.kind() == ErrorKind::NotFound {
            GameError::InvalidStateTransition("Asset file missing".to_string())
        } else {
            GameError::NetworkTimeout
        }
    }
}

impl Error for GameError {}

pub fn process_player_action(has_gold: bool, current_quest: &str) -> Result<(), Box<dyn Error>> {
    if !has_gold {
        return Err(Box::new(GameError::InsufficientResources("Gold".to_string())));
    }
    if current_quest.is_empty() {
        return Err(Box::new(GameError::InvalidStateTransition("Must accept a quest first".to_string())));
    }
    Ok(())
}

use std::fmt::{self, Display};
use std::error::Error;

#[derive(Debug)]
enum CoordinateError {
    MissingField(&'static str),
    OutOfRange { field: &'static str, value: f64 },
}

impl Display for CoordinateError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            CoordinateError::MissingField(field) => write!(f, "Error: Missing required data field: {}", field),
            CoordinateError::OutOfRange { field, value } => write!(f, "Error: Invalid range for {} with value: {}", field, value),
        }
    }
}

impl Error for CoordinateError {}

struct Point {
    id: u32,
    lat: f64,
    lon: f64,
}

fn validate_point(point: &Point) -> Result<(), Box<dyn Error>> {
    if point.lat < -90.0 || point.lat > 90.0 {
        return Err(Box::new(CoordinateError::OutOfRange { field: "latitude", value: point.lat }));
    }

    if point.lon < -180.0 || point.lon > 180.0 {
        return Err(Box::new(CoordinateError::OutOfRange { field: "longitude", value: point.lon }));
    }

    Ok(())
}

fn process_query_data(data: Option<Point>) -> Result<u32, Box<dyn Error>> {
    let point = match data {
        Some(p) => p,
        None => return Err(Box::new(CoordinateError::MissingField("Point object"))),
    };

    validate_point(&point)?;
    Ok(point.id)
}

fn main() {
    let valid_data = Some(Point { id: 1, lat: 34.0, lon: -118.0 });
    match process_query_data(valid_data) {
        Ok(id) => println!("Successfully processed point with ID: {}", id),
        Err(e) => eprintln!("Failed to process query data: {}", e),
    }

    let invalid_lat = Some(Point { id: 2, lat: 95.0, lon: 0.0 });
    match process_query_data(invalid_lat) {
        Ok(_) => (),
        Err(e) => eprintln!("Caught expected error for point 2: {}", e),
    }

    let missing_data = None;
    match process_query_data(missing_data) {
        Ok(_) => (),
        Err(e) => eprintln!("Caught expected error for missing data: {}", e),
    }
}

use std::fmt::{self, Display};
use std::io::{self, ErrorKind};

#[derive(Debug)]
enum PacketError {
    Io(io::Error),
    FormatMismatch(String),
}

impl Display for PacketError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            PacketError::Io(e) => write!(f, "IO Error occurred: {}", e),
            PacketError::FormatMismatch(s) => write!(f, "Data format error: {}", s),
        }
    }
}

impl std::error::Error for PacketError {}

impl From<io::Error> for PacketError {
    fn from(err: io::Error) -> Self {
        PacketError::Io(err)
    }
}

struct NetworkPacket {
    source_ip: String,
    destination_ip: String,
    payload_size: u32,
}

impl NetworkPacket {
    fn parse_data(raw_bytes: &[u8]) -> Result<Self, PacketError> {
        if raw_bytes.len() < 12 {
            return Err(PacketError::FormatMismatch("Insufficient header data".to_string()));
        }

        let source_ip = format!("{}.{}.{}.{}", raw_bytes[0], raw_bytes[1], raw_bytes[2], raw_bytes[3]);
        let destination_ip = format!("{}.{}.{}.{}", raw_bytes[4], raw_bytes[5], raw_bytes[6], raw_bytes[7]);
        let payload_size = u32::from_be_bytes([raw_bytes[8], raw_bytes[9], raw_bytes[10], raw_bytes[11]]);

        if payload_size == 0 {
            return Err(PacketError::FormatMismatch("Zero payload size detected".to_string()));
        }

        Ok(NetworkPacket {
            source_ip,
            destination_ip,
            payload_size,
        })
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let good_data = vec![0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x10, 0x00, 0x00, 0x10];
    let bad_data = vec![0x01, 0x02, 0x03];

    match NetworkPacket::parse_data(&good_data) {
        Ok(packet) => println!("Successfully parsed packet from {} to {}", packet.source_ip, packet.destination_ip),
        Err(e) => eprintln!("Failed to parse good data: {}", e),
    }

    match NetworkPacket::parse_data(&bad_data) {
        Ok(_) => println!("Should not succeed"),
        Err(e) => println!("Correctly caught error when parsing insufficient data: {}", e),
    }

    Ok(())
}
